const query    = $('Serve Form Webhook (GET)').first().json.query || {};
const token    = (query.token    || '').trim();
const tgid     = (query.tgid     || '').trim();
const nickname = decodeURIComponent(query.nickname || 'there');
const returning = (query.returning || '').trim() === 'true';

// Load draft if available
const draftRow   = $('Load Draft').first().json;
const draftData  = (draftRow && draftRow.draft_data && typeof draftRow.draft_data === 'object')
  ? draftRow.draft_data : {};
const draftStep  = (draftRow && draftRow.last_step && draftRow.last_step > 1)
  ? parseInt(draftRow.last_step) : 0;
const hasDraft   = draftStep > 1 && Object.keys(draftData).length > 0;

const LOGO_B64 = 'data:image/png;base64,';

if (!token || !tgid) {
  return {
    json: {
      html_content: `<!DOCTYPE html><html><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>MySquad</title><style>*{box-sizing:border-box;margin:0;padding:0}:root{--accent:#F13A01;--accent-dark:#C42D00}body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#F5F4F2;color:#1C1917;display:flex;align-items:center;justify-content:center;min-height:100vh;padding:24px}@media(prefers-color-scheme:dark){body{background:#1A1714;color:#F5F4F2}}.card{text-align:center;max-width:420px;width:100%;background:#fff;border-radius:20px;padding:40px 28px;box-shadow:0 8px 32px rgba(0,0,0,.08)}@media(prefers-color-scheme:dark){.card{background:#252220;box-shadow:0 8px 32px rgba(0,0,0,.4)}}.logo{width:64px;height:64px;border-radius:50%;margin:0 auto 20px;display:block}h2{color:var(--accent);margin:0 0 10px;font-size:21px;font-weight:700}p{color:#78716C;font-size:14px;line-height:1.7}@media(prefers-color-scheme:dark){p{color:#A8A29E}}</style></head><body><div class="card"><img class="logo" src="${LOGO_B64}" alt="MySquad"/><h2>Link expired column_1/h2><p>This setup link has expired or has already been used.<br/><br/>Go back to Telegram column_2strong>/start</strong> to get a fresh link.</p></div></body></html>`
    }
  };
}

const SUBMIT_URL = '[URL]';

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1.0"/>
<title>MySquad — Set Up Your Agent</title>
<style>
/* ── Design tokens ──────────────────────────────────── */
:root {
  --accent: #F13A01;
  --accent-dark: #C42D00;
  --accent-light: #FEE8E0;
  --accent-pale: #FFF5F2;
  --text: #1C1917;
  --text-muted: #6B6560;
  --text-light: #A8A29E;
  --border: #E8E5E2;
  --border-focus: #F13A01;
  --bg: #F5F4F2;
  --surface: #FFFFFF;
  --surface-2: #FAFAF8;
  --error: #DC2626;
  --success: #16A34A;
  --radius: 16px;
  --radius-sm: 10px;
  --radius-xs: 7px;
  --shadow-sm: 0 1px 3px rgba(0,0,0,.06), 0 1px 2px rgba(0,0,0,.04);
  --shadow-md: 0 4px 16px rgba(0,0,0,.08), 0 1px 4px rgba(0,0,0,.04);
  --shadow-lg: 0 12px 40px rgba(0,0,0,.10), 0 4px 12px rgba(0,0,0,.06);
  --transition: 200ms cubic-bezier(.4,0,.2,1);
}
@media (prefers-color-scheme: dark) {
  :root {
    --accent: #F13A01;
    --accent-dark: #FF5520;
    --accent-light: rgba(241,58,1,.18);
    --accent-pale: rgba(241,58,1,.08);
    --text: #F0EDE8;
    --text-muted: #9C9189;
    --text-light: #6B6560;
    --border: #2E2926;
    --border-focus: #F13A01;
    --bg: #141210;
    --surface: #1E1B18;
    --surface-2: #252220;
    --error: #F87171;
    --success: #4ADE80;
    --shadow-sm: 0 1px 3px rgba(0,0,0,.3);
    --shadow-md: 0 4px 20px rgba(0,0,0,.35);
    --shadow-lg: 0 12px 48px rgba(0,0,0,.5);
  }
}

/* ── Reset & base ───────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { -webkit-text-size-adjust: 100%; }
body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Inter', sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding-bottom: 80px;
  transition: background var(--transition), color var(--transition);
}

/* ── Header ─────────────────────────────────────────── */
.header {
  width: 100%;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  padding: 12px 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  position: sticky;
  top: 0;
  z-index: 100;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}
@media (prefers-color-scheme: dark) {
  .header {
    background: rgba(30,27,24,.92);
  }
}
.header-logo-img { width: 32px; height: 32px; border-radius: 50%; flex-shrink: 0; }
.header-wordmark { font-size: 17px; font-weight: 700; color: var(--text); letter-spacing: -.3px; }
.header-wordmark span { font-weight: 400; color: var(--text-muted); font-size: 14px; }
.header-badge {
  margin-left: auto;
  font-size: 11px;
  font-weight: 600;
  color: var(--accent);
  background: var(--accent-pale);
  border: 1px solid var(--accent-light);
  border-radius: 20px;
  padding: 3px 9px;
  letter-spacing: .2px;
}

/* ── Progress ────────────────────────────────────────── */
.progress-wrap { width: 100%; max-width: 560px; padding: 24px 20px 0; }
.progress-steps { display: flex; align-items: center; }
.step-dot-wrap { display: flex; flex-direction: column; align-items: center; gap: 5px; flex: 0 0 auto; }
.step-dot {
  width: 30px; height: 30px; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 12px; font-weight: 700;
  border: 2px solid var(--border);
  background: var(--surface);
  color: var(--text-light);
  transition: all .25s ease;
}
.step-dot.active {
  border-color: var(--accent);
  background: var(--accent);
  color: #fff;
  box-shadow: 0 0 0 4px var(--accent-pale);
}
.step-dot.done {
  border-color: var(--accent);
  background: var(--accent-pale);
  color: var(--accent);
}
.step-label { font-size: 10px; color: var(--text-light); white-space: nowrap; font-weight: 500; }
.step-label.active { color: var(--accent); font-weight: 700; }
.step-line { flex: 1; height: 2px; background: var(--border); margin-bottom: 17px; border-radius: 2px; transition: background .3s; }
.step-line.done { background: var(--accent); }

/* ── Card ────────────────────────────────────────────── */
.card {
  width: 100%; max-width: 560px;
  background: var(--surface);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
  margin: 20px 16px 0;
  padding: 28px 24px 24px;
  border: 1px solid var(--border);
  transition: background var(--transition), border-color var(--transition);
}
.card-eyebrow { font-size: 11px; font-weight: 700; color: var(--accent); text-transform: uppercase; letter-spacing: 1px; margin-bottom: 6px; }
.card-title { font-size: 22px; font-weight: 800; color: var(--text); margin-bottom: 6px; line-height: 1.2; }
.card-subtitle { font-size: 14px; color: var(--text-muted); line-height: 1.6; margin-bottom: 24px; }

/* ── Fields ──────────────────────────────────────────── */
.field { margin-bottom: 20px; }
.field:last-child { margin-bottom: 0; }
label { display: block; font-size: 13px; font-weight: 600; color: var(--text); margin-bottom: 7px; }
label .required { color: var(--accent); margin-left: 2px; }
label .hint { font-weight: 400; color: var(--text-muted); font-size: 12px; margin-left: 4px; }
input[type=text], input[type=email], input[type=tel], input[type=password], textarea {
  width: 100%;
  padding: 11px 14px;
  border: 1.5px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 15px;
  color: var(--text);
  background: var(--surface-2);
  outline: none;
  font-family: inherit;
  appearance: none;
  transition: border-color .18s, box-shadow .18s, background .18s;
  -webkit-appearance: none;
}
input:focus, textarea:focus {
  border-color: var(--border-focus);
  box-shadow: 0 0 0 3px rgba(241,58,1,.12);
  background: var(--surface);
}
input.error, textarea.error { border-color: var(--error) !important; box-shadow: none !important; }
input.match { border-color: var(--success) !important; box-shadow: 0 0 0 3px rgba(22,163,74,.1) !important; }
textarea { resize: vertical; min-height: 100px; line-height: 1.6; }
.field-error { font-size: 12px; color: var(--error); margin-top: 5px; display: none; align-items: center; gap: 4px; }
.field-error.show { display: flex; }
.pw-match-hint { font-size: 12px; margin-top: 5px; display: none; align-items: center; gap: 4px; }
.pw-match-hint.show { display: flex; }
.pw-match-hint.ok { color: var(--success); }
.pw-match-hint.no { color: var(--error); }
.char-count { font-size: 11px; color: var(--text-light); text-align: right; margin-top: 4px; }
.section-divider { border: none; border-top: 1px solid var(--border); margin: 20px 0; }
.inline-row { display: flex; gap: 12px; }
.inline-row .field { flex: 1; }
.password-wrap { position: relative; }
.password-wrap input { padding-right: 46px; }
.toggle-pw {
  position: absolute; right: 13px; top: 50%; transform: translateY(-50%);
  cursor: pointer; font-size: 16px; color: var(--text-muted);
  user-select: none; transition: color .15s;
}
.toggle-pw:hover { color: var(--accent); }

/* ── Chips ───────────────────────────────────────────── */
.chip-group { display: flex; flex-wrap: wrap; gap: 8px; }
.chip {
  padding: 8px 15px;
  border-radius: 30px;
  border: 1.5px solid var(--border);
  background: var(--surface-2);
  font-size: 13px;
  color: var(--text-muted);
  cursor: pointer;
  transition: all .18s;
  user-select: none;
  font-weight: 500;
  letter-spacing: -.1px;
}
.chip:hover { border-color: var(--accent); color: var(--accent); background: var(--accent-pale); }
.chip.selected {
  border-color: var(--accent);
  background: var(--accent);
  color: #fff;
  font-weight: 600;
  box-shadow: 0 2px 8px rgba(241,58,1,.25);
}

/* ── Day chips ────────────────────────────────────────── */
.day-grid { display: flex; gap: 6px; flex-wrap: wrap; }
.day-chip {
  width: 42px; height: 42px; border-radius: 50%;
  border: 1.5px solid var(--border);
  background: var(--surface-2);
  font-size: 11px; font-weight: 700;
  color: var(--text-muted);
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  transition: all .18s; user-select: none;
}
.day-chip:hover { border-color: var(--accent); color: var(--accent); }
.day-chip.selected { border-color: var(--accent); background: var(--accent); color: #fff; box-shadow: 0 2px 8px rgba(241,58,1,.25); }

/* ── Time ─────────────────────────────────────────────── */
.time-row { display: flex; gap: 10px; align-items: center; }
.time-row .sep { color: var(--text-muted); font-size: 14px; font-weight: 600; }
input[type=time] {
  flex: 1;
  padding: 11px 14px;
  border: 1.5px solid var(--border);
  border-radius: var(--radius-sm);
  font-size: 15px; font-family: inherit;
  color: var(--text);
  background: var(--surface-2);
  outline: none;
  transition: border-color .18s, box-shadow .18s;
}
input[type=time]:focus { border-color: var(--border-focus); box-shadow: 0 0 0 3px rgba(241,58,1,.12); }

/* ── Conditional fields ───────────────────────────────── */
.conditional-field { display: none; margin-top: 18px; }
.conditional-field.show { display: block; animation: slideDown .22s ease; }
@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}
.other-input-wrap { display: none; margin-top: 10px; }
.other-input-wrap.show { display: block; animation: slideDown .2s ease; }

/* ── Info box ─────────────────────────────────────────── */
.info-box {
  background: var(--accent-pale);
  border: 1px solid var(--accent-light);
  border-radius: var(--radius-sm);
  padding: 12px 14px;
  font-size: 13px;
  color: var(--accent-dark);
  line-height: 1.6;
  margin-bottom: 18px;
}
@media (prefers-color-scheme: dark) {
  .info-box { color: #FF7A50; }
}

/* ── Deposit custom input ─────────────────────────────── */
.deposit-custom-wrap { display: none; margin-top: 10px; }
.deposit-custom-wrap.show { display: block; animation: slideDown .2s ease; }

/* ── File upload ──────────────────────────────────────── */
.file-upload-box {
  border: 1.5px dashed var(--border);
  border-radius: var(--radius-sm);
  padding: 18px;
  background: var(--surface-2);
  cursor: pointer;
  transition: border-color .18s, background .18s;
  position: relative;
  text-align: center;
}
.file-upload-box:hover { border-color: var(--accent); background: var(--accent-pale); }
.file-upload-box input[type=file] { position: absolute; inset: 0; opacity: 0; cursor: pointer; width: 100%; height: 100%; }
.file-upload-icon { font-size: 28px; margin-bottom: 8px; }
.file-upload-text { font-size: 13px; color: var(--text-muted); line-height: 1.5; }
.file-upload-text strong { color: var(--accent); }
.file-chosen {
  margin-top: 8px; padding: 9px 13px;
  background: var(--accent-pale);
  border: 1px solid var(--accent-light);
  border-radius: var(--radius-xs);
  font-size: 13px; color: var(--accent);
  display: none; align-items: center; gap: 8px;
}
.file-chosen.show { display: flex; }
.file-chosen-name { flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.file-remove { cursor: pointer; font-weight: 800; font-size: 15px; color: var(--error); flex-shrink: 0; opacity: .7; transition: opacity .15s; }
.file-remove:hover { opacity: 1; }

/* ── Product/portfolio cards ─────────────────────────── */
.media-cards { display: flex; flex-direction: column; gap: 12px; }
.media-card { border: 1.5px solid var(--border); border-radius: var(--radius-sm); padding: 14px; background: var(--surface-2); position: relative; transition: border-color .18s; }
.media-card:hover { border-color: var(--accent-light); }
.media-card-inner { display: flex; gap: 12px; align-items: flex-start; }
.media-img-box {
  width: 68px; height: 68px; border-radius: 10px;
  border: 1.5px dashed var(--border);
  display: flex; align-items: center; justify-content: center;
  overflow: hidden; flex-shrink: 0;
  cursor: pointer; background: var(--surface); position: relative;
  transition: border-color .18s;
}
.media-img-box:hover { border-color: var(--accent); }
.media-img-box img { width: 100%; height: 100%; object-fit: cover; border-radius: 8px; }
.img-ph { display: flex; flex-direction: column; align-items: center; gap: 3px; pointer-events: none; }
.img-ph-icon { font-size: 22px; color: var(--text-light); }
.img-ph-label { font-size: 9px; color: var(--text-light); font-weight: 600; text-transform: uppercase; letter-spacing: .3px; }
.media-img-box input[type=file] { position: absolute; inset: 0; opacity: 0; cursor: pointer; }
.media-card-fields { flex: 1; }
.remove-card {
  position: absolute; top: 10px; right: 10px;
  width: 22px; height: 22px; border-radius: 50%;
  background: var(--border); border: none; cursor: pointer;
  font-size: 13px; color: var(--text-muted);
  display: flex; align-items: center; justify-content: center;
  transition: background .15s, color .15s;
}
.remove-card:hover { background: rgba(220,38,38,.15); color: var(--error); }
.add-media-btn {
  display: flex; align-items: center; gap: 8px;
  color: var(--accent); font-size: 14px; font-weight: 600;
  cursor: pointer; padding: 10px 0;
  background: none; border: none; font-family: inherit;
  transition: opacity .15s;
}
.add-media-btn:disabled { opacity: .4; cursor: not-allowed; }
.add-media-btn-icon {
  width: 24px; height: 24px; border-radius: 50%;
  background: var(--accent-pale); border: 1.5px solid var(--accent-light);
  display: flex; align-items: center; justify-content: center;
  font-size: 16px; color: var(--accent); line-height: 1;
}

/* ── Tone cards ────────────────────────────────────────── */
.tone-cards { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
@media(max-width:480px) { .tone-cards { grid-template-columns: 1fr; } }
.tone-card {
  border: 1.5px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 14px; cursor: pointer;
  transition: all .18s; background: var(--surface-2);
}
.tone-card:hover { border-color: var(--accent); background: var(--accent-pale); }
.tone-card.selected { border-color: var(--accent); background: var(--accent-pale); }
.tone-card-emoji { font-size: 22px; margin-bottom: 6px; }
.tone-card-title { font-size: 14px; font-weight: 700; color: var(--text); margin-bottom: 3px; }
.tone-card.selected .tone-card-title { color: var(--accent); }
.tone-card-desc { font-size: 12px; color: var(--text-muted); line-height: 1.4; }

/* ── Pages ─────────────────────────────────────────────── */
.page { display: none; }
.page.active { display: block; animation: fadeSlide .25s ease; }
@keyframes fadeSlide {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ── Review ─────────────────────────────────────────────── */
.review-section { margin-bottom: 20px; }
.review-section-title {
  font-size: 11px; font-weight: 700;
  color: var(--accent); text-transform: uppercase; letter-spacing: .8px;
  margin-bottom: 10px; padding-bottom: 8px;
  border-bottom: 1px solid var(--border);
  display: flex; justify-content: space-between; align-items: center;
}
.review-row { display: flex; gap: 10px; padding: 8px 0; font-size: 14px; border-bottom: 1px solid var(--surface-2); }
.review-row:last-child { border-bottom: none; }
.review-key { color: var(--text-muted); flex: 0 0 120px; font-size: 13px; }
.review-val { color: var(--text); flex: 1; word-break: break-word; font-weight: 500; }
.review-edit { color: var(--accent); font-size: 12px; font-weight: 600; cursor: pointer; white-space: nowrap; flex-shrink: 0; }
.review-edit:hover { text-decoration: underline; }

/* ── Buttons ─────────────────────────────────────────────── */
.btn-row { display: flex; gap: 10px; margin-top: 28px; justify-content: space-between; align-items: center; }
.btn {
  padding: 13px 24px; border-radius: var(--radius-sm);
  font-size: 15px; font-weight: 700;
  cursor: pointer; border: none; font-family: inherit;
  transition: all .18s; display: flex; align-items: center; gap: 6px;
}
.btn-primary {
  background: var(--accent); color: #fff;
  flex: 1; justify-content: center;
  box-shadow: 0 2px 12px rgba(241,58,1,.3);
}
.btn-primary:hover { background: var(--accent-dark); box-shadow: 0 4px 16px rgba(241,58,1,.4); transform: translateY(-1px); }
.btn-primary:active { transform: translateY(0); }
.btn-primary:disabled { opacity: .5; cursor: not-allowed; transform: none; box-shadow: none; }
.btn-ghost { background: transparent; color: var(--text-muted); padding: 13px 14px; }
.btn-ghost:hover { color: var(--text); }

/* ── Credits badge ───────────────────────────────────────── */
.credits-badge {
  background: linear-gradient(135deg, var(--accent-pale), var(--accent-light));
  border: 1px solid var(--accent-light);
  border-radius: var(--radius-sm);
  padding: 14px 16px; margin-top: 18px;
  font-size: 13px; color: var(--accent-dark);
  line-height: 1.6; display: flex; gap: 10px; align-items: flex-start;
}
@media (prefers-color-scheme: dark) { .credits-badge { color: #FF7A50; } }
.credits-badge-icon { font-size: 20px; flex-shrink: 0; margin-top: 1px; }

/* ── Loading overlay ─────────────────────────────────────── */
.loading-overlay {
  display: none; position: fixed; inset: 0;
  background: rgba(20,18,16,.7); backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  z-index: 200; flex-direction: column;
  align-items: center; justify-content: center; gap: 20px;
}
.loading-overlay.show { display: flex; }
.loading-card {
  background: var(--surface); border-radius: 20px;
  padding: 36px 40px; text-align: center;
  box-shadow: var(--shadow-lg); border: 1px solid var(--border);
  display: flex; flex-direction: column; align-items: center; gap: 16px;
}
.loading-logo { width: 56px; height: 56px; border-radius: 50%; animation: pulse 1.2s ease-in-out infinite; }
@keyframes pulse { 0%,100%{transform:scale(1);opacity:1} 50%{transform:scale(1.08);opacity:.85} }
.loading-text { font-size: 15px; color: var(--text-muted); font-weight: 500; }

/* ── Success screen ──────────────────────────────────────── */
.success-screen {
  display: none; flex-direction: column;
  align-items: center; text-align: center;
  padding: 60px 24px; max-width: 480px; margin: 0 auto;
}
.success-screen.show { display: flex; animation: fadeSlide .4s ease; }
.success-logo-wrap {
  width: 96px; height: 96px; border-radius: 50%;
  background: var(--accent-pale);
  border: 3px solid var(--accent-light);
  display: flex; align-items: center; justify-content: center;
  margin-bottom: 24px;
  box-shadow: 0 0 0 8px rgba(241,58,1,.06);
}
.success-logo { width: 68px; height: 68px; border-radius: 50%; }
.success-title { font-size: 28px; font-weight: 800; color: var(--text); margin-bottom: 12px; }
.success-sub { font-size: 16px; color: var(--text-muted); line-height: 1.7; }
.success-username { color: var(--accent); font-weight: 700; }

/* ── Responsive ──────────────────────────────────────────── */
@media(max-width:600px) {
  .card { margin: 16px 12px 0; padding: 22px 18px 20px; }
  .progress-wrap { padding: 18px 14px 0; }
  .inline-row { flex-direction: column; gap: 0; }
  .header { padding: 10px 14px; }
  .header-badge { display: none; }
}
</style>
</head>
<body>

<div class="header">
  <img class="header-logo-img" src="${LOGO_B64}" alt="MySquad"/>
  <div class="header-wordmark">MySquad <span>— Your AI Business Squad</span></div>
  <div class="header-badge">Setup</div>
</div>

<div id="main-content" style="width:100%;max-width:560px;display:flex;flex-direction:column;align-items:stretch">

  <div class="progress-wrap" id="progress-wrap">
    <div class="progress-steps">
      <div class="step-dot-wrap"><div class="step-dot active" id="dot-1">1</div><div class="step-label active" id="lbl-1">Account</div></div>
      <div class="step-line" id="line-1"></div>
      <div class="step-dot-wrap"><div class="step-dot" id="dot-2">2</div><div class="step-label" id="lbl-2">Business</div></div>
      <div class="step-line" id="line-2"></div>
      <div class="step-dot-wrap"><div class="step-dot" id="dot-3">3</div><div class="step-label" id="lbl-3">Catalogue</div></div>
      <div class="step-line" id="line-3"></div>
      <div class="step-dot-wrap"><div class="step-dot" id="dot-4">4</div><div class="step-label" id="lbl-4">Photos</div></div>
      <div class="step-line" id="line-4"></div>
      <div class="step-dot-wrap"><div class="step-dot" id="dot-5">5</div><div class="step-label" id="lbl-5">Agent</div></div>
      <div class="step-line" id="line-5"></div>
      <div class="step-dot-wrap"><div class="step-dot" id="dot-6">6</div><div class="step-label" id="lbl-6">Review</div></div>
    </div>
  </div>

  <!-- PAGE 1: Account -->
  <div class="page active" id="page-1">
    <div class="card">
      <div class="card-eyebrow">Step 1 of 5</div>
      <div class="card-title">Let's set you up 👋</div>
      <div class="card-subtitle">A few details to create your account. Takes about 4 minutes total. Your link stays active for 72 hours — come back anytime if you need a break.</div>
      <div class="inline-row">
        <div class="field"><label>First name <span class="required">*</span></label><input type="text" id="first_name" placeholder="Amaka" autocomplete="given-name"/><div class="field-error" id="err-first_name">⚠ Please enter your first name</div></div>
        <div class="field"><label>Last name <span class="required">*</span></label><input type="text" id="last_name" placeholder="Okafor" autocomplete="family-name"/><div class="field-error" id="err-last_name">⚠ Please enter your last name</div></div>
      </div>
      <div class="field"><label>Email address <span class="required">*</span></label><input type="email" id="email" placeholder="[EMAIL]" autocomplete="email"/><div class="field-error" id="err-email">⚠ Please enter a valid email</div></div>
      <div class="field"><label>WhatsApp number <span class="required">*</span> <span class="hint">— for your WhatsApp channel later</span></label><input type="tel" id="whatsapp_number" placeholder="[PHONE]" oninput="normalisePhone(this)"/><div class="field-error" id="err-whatsapp_number">⚠ Please enter a valid phone number</div><div id="wa-format-hint" style="font-size:12px;color:var(--success);margin-top:4px;display:none"></div></div>
      <div class="field"><label>City &amp; State <span class="required">*</span></label><input type="text" id="location" placeholder="Lekki, Lagos"/><div class="field-error" id="err-location">⚠ Please enter your location</div></div>
      <hr class="section-divider"/>
      <div class="field"><label>Username <span class="required">*</span> <span class="hint">— for your profile page</span></label><input type="text" id="username" placeholder="amaka_styles" autocomplete="username" oninput="this.value=this.value.toLowerCase().replace(/[^a-z0-9_]/g,'')"/><div class="field-error" id="err-username">⚠ 3–30 characters, letters/numbers/underscore only</div></div>
      <div class="field">
        <label>Password <span class="required">*</span></label>
        <div class="password-wrap"><input type="password" id="password" placeholder="At least 8 characters" autocomplete="new-password" oninput="checkPwMatch()"/><span class="toggle-pw" onclick="togglePw('password',this)">👁</span></div>
        <div class="field-error" id="err-password">⚠ Password must be at least 8 characters</div>
      </div>
      <div class="field">
        <label>Confirm password <span class="required">*</span></label>
        <div class="password-wrap"><input type="password" id="confirm_password" placeholder="Same as above" autocomplete="new-password" oninput="checkPwMatch()"/><span class="toggle-pw" onclick="togglePw('confirm_password',this)">👁</span></div>
        <div class="pw-match-hint" id="pw-match-hint"></div>
        <div class="field-error" id="err-confirm_password">⚠ Passwords do not match</div>
      </div>
      <div class="btn-row"><div></div><button class="btn btn-primary" onclick="goNext(1)">Continue →</button></div>
    </div>
  </div>

  <!-- PAGE 2: Business -->
  <div class="page" id="page-2">
    <div class="card">
      <div class="card-eyebrow">Step 2 of 5</div>
      <div class="card-title">Your business 🏪</div>
      <div class="card-subtitle">This helps your agent know exactly who it's representing.</div>

      <div class="field"><label>Business name <span class="required">*</span></label><input type="text" id="business_name" placeholder="Amaka Styles &amp; More"/><div class="field-error" id="err-business_name">⚠ Please enter your business name</div></div>

      <div class="field">
        <label>What best describes your business? <span class="required">*</span></label>
        <div class="chip-group" id="business_type_chips">
          <div class="chip" onclick="selBizType(this,'product')">🛍 Retail</div>
          <div class="chip" onclick="selBizType(this,'product')">🍔 Food &amp; Drinks</div>
          <div class="chip" onclick="selBizType(this,'hybrid')">👗 Fashion &amp; Beauty</div>
          <div class="chip" onclick="selBizType(this,'service')">💼 Services</div>
          <div class="chip" onclick="selBizType(this,'service')">📱 Content Creator</div>
          <div class="chip" onclick="selBizType(this,'hybrid')">🏗 Construction / Real Estate</div>
          <div class="chip" onclick="selBizType(this,'other')">📦 Other</div>
        </div>
        <div class="other-input-wrap" id="other-input-wrap">
          <input type="text" id="business_type_other" placeholder="e.g. Agricultural supplies, Printing…" oninput="onOtherTypeInput(this.value)"/>
        </div>
        <input type="hidden" id="business_type"/>
        <input type="hidden" id="business_mode" value=""/>
        <div class="field-error" id="err-business_type">⚠ Please select or describe your business type</div>
      </div>

      <div class="conditional-field" id="also-services-wrap">
        <label>Do you also offer services or appointments? <span class="hint">— e.g. alterations, consultations</span></label>
        <div class="chip-group">
          <div class="chip" id="also-svc-yes" onclick="setAlsoServices(true)">Yes, I offer services too</div>
          <div class="chip" id="also-svc-no" onclick="setAlsoServices(false)">No, products only</div>
        </div>
      </div>

      <div class="conditional-field" id="also-products-wrap">
        <label>Do you also sell physical products? <span class="hint">— e.g. hair products, accessories</span></label>
        <div class="chip-group">
          <div class="chip" id="also-prod-yes" onclick="setAlsoProducts(true)">Yes, I sell products too</div>
          <div class="chip" id="also-prod-no" onclick="setAlsoProducts(false)">No, services only</div>
        </div>
      </div>

      <div class="conditional-field" id="service-fields-wrap">
        <hr class="section-divider"/>
        <div class="info-box">📋 Since you offer services, a few extra questions help your agent handle bookings correctly.</div>
        <div class="field">
          <label>How do clients come to you?</label>
          <div class="chip-group">
            <div class="chip" onclick="selSingle(this,'service_delivery_mode','client_comes_to_us')">🏠 Clients come to me</div>
            <div class="chip" onclick="selSingle(this,'service_delivery_mode','we_go_to_client')">🚗 I go to clients</div>
            <div class="chip" onclick="selSingle(this,'service_delivery_mode','both')">↔ Both / depends</div>
          </div>
          <input type="hidden" id="service_delivery_mode"/>
        </div>
        <div class="field">
          <label>Typical appointment duration <span class="hint">— optional</span></label>
          <div class="chip-group">
            <div class="chip" onclick="selSingle(this,'typical_session_duration','30min')">30 mins</div>
            <div class="chip" onclick="selSingle(this,'typical_session_duration','1hr')">1 hour</div>
            <div class="chip" onclick="selSingle(this,'typical_session_duration','2hr')">2 hours</div>
            <div class="chip" onclick="selSingle(this,'typical_session_duration','half_day')">Half day</div>
            <div class="chip" onclick="selSingle(this,'typical_session_duration','full_day')">Full day</div>
            <div class="chip" onclick="selSingle(this,'typical_session_duration','varies')">Varies</div>
          </div>
          <input type="hidden" id="typical_session_duration"/>
        </div>
        <div class="field">
          <label>Deposit to confirm bookings?</label>
          <div class="chip-group">
            <div class="chip" onclick="selDeposit(this,'none')">No deposit</div>
            <div class="chip" onclick="selDeposit(this,'50_percent')">50% upfront</div>
            <div class="chip" onclick="selDeposit(this,'full_payment')">Full payment</div>
            <div class="chip" onclick="selDeposit(this,'custom')">Custom amount</div>
          </div>
          <input type="hidden" id="deposit_policy" value="none"/>
          <div class="deposit-custom-wrap" id="deposit-custom-wrap">
            <input type="text" id="deposit_custom_text" placeholder="e.g. ₦5,000 non-refundable booking fee" oninput="S.deposit_custom=this.value"/>
          </div>
        </div>
        <div class="field">
          <label>Cancellation / rescheduling policy <span class="hint">— optional</span></label>
          <textarea id="cancellation_policy" placeholder="e.g. Cancel 24 hours before for a full refund. Same-day cancellations forfeit the deposit." maxlength="300" oninput="charCount(this,'cancel-c',300)"></textarea>
          <div class="char-count"><span id="cancel-c">0</span>/300</div>
        </div>
      </div>

      <div class="conditional-field" id="payment-mode-wrap">
        <div class="field">
          <label>How do customers pay? <span class="required">*</span></label>
          <div class="chip-group">
            <div class="chip" onclick="selSingle(this,'payment_mode','pay_before')">💳 Pay before delivery</div>
            <div class="chip" onclick="selSingle(this,'payment_mode','pay_on_delivery')">🚪 Pay on delivery</div>
            <div class="chip" onclick="selSingle(this,'payment_mode','both')">↔ Customer's choice</div>
          </div>
          <input type="hidden" id="payment_mode" value="pay_before"/>
          <div class="field-error" id="err-payment_mode">⚠ Please select a payment option</div>
        </div>
      </div>

      <div class="field"><label>Where is your business based? <span class="required">*</span></label><input type="text" id="business_location" placeholder="Surulere, Lagos"/><div class="field-error" id="err-business_location">⚠ Please enter your business location</div></div>

      <div class="field">
        <label>How do customers reach you? <span class="hint">(select all that apply)</span></label>
        <div class="chip-group">
          <div class="chip" onclick="togMulti(this,'reach_channels')">WhatsApp</div>
          <div class="chip" onclick="togMulti(this,'reach_channels')">Instagram</div>
          <div class="chip" onclick="togMulti(this,'reach_channels')">Facebook</div>
          <div class="chip" onclick="togMulti(this,'reach_channels')">Walk-in</div>
          <div class="chip" onclick="togMulti(this,'reach_channels')">Delivery</div>
          <div class="chip" onclick="togMulti(this,'reach_channels')">Phone calls</div>
        </div>
        <input type="hidden" id="reach_channels" value="[]"/>
      </div>

      <div class="field"><label>About your business <span class="required">*</span> <span class="hint">— who are your customers? what makes you different?</span></label><textarea id="business_description" placeholder="e.g. I sell ready-to-wear outfits in Lagos. My customers are working women. Known for quick turnaround and quality fabrics." maxlength="800" oninput="charCount(this,'desc-c',800)"></textarea><div class="char-count"><span id="desc-c">0</span>/800</div><div class="field-error" id="err-business_description">⚠ Please tell us a bit about your business (min 30 characters)</div></div>

      <div class="field"><label>Operating days</label>
        <div class="day-grid">
          <div class="day-chip" onclick="togDay(this,'Mon')">Mon</div>
          <div class="day-chip" onclick="togDay(this,'Tue')">Tue</div>
          <div class="day-chip" onclick="togDay(this,'Wed')">Wed</div>
          <div class="day-chip" onclick="togDay(this,'Thu')">Thu</div>
          <div class="day-chip" onclick="togDay(this,'Fri')">Fri</div>
          <div class="day-chip" onclick="togDay(this,'Sat')">Sat</div>
          <div class="day-chip" onclick="togDay(this,'Sun')">Sun</div>
        </div>
        <input type="hidden" id="operating_days" value="[]"/>
      </div>

      <div class="field"><label>Opening &amp; closing time</label>
        <div class="time-row"><input type="time" id="open_time" value="08:00"/><span class="sep">to</span><input type="time" id="close_time" value="18:00"/></div>
      </div>

      <div class="btn-row"><button class="btn btn-ghost" onclick="goBack(2)">← Back</button><button class="btn btn-primary" onclick="goNext(2)">Continue →</button></div>
    </div>
  </div>

  <!-- PAGE 3: Catalogue -->
  <div class="page" id="page-3">
    <div class="card">
      <div class="card-eyebrow">Step 3 of 6</div>
      <div class="card-title" id="p3-title">What do you sell? 📦</div>
      <div class="card-subtitle" id="p3-subtitle">Help your agent know your products and prices so it can assist customers.</div>

      <div class="field">
        <label id="p3-catalogue-label">List your products / services &amp; prices <span class="hint">— type freely</span></label>
        <textarea id="catalogue_text" placeholder="e.g.&#10;Ankara gown – ₦15,000&#10;Aso-ebi tailoring from ₦25,000&#10;Ready-made blouses – ₦8,000" maxlength="1200" oninput="charCount(this,'cat-c',1200)"></textarea>
        <div class="char-count"><span id="cat-c">0</span>/1200</div>
      </div>

      <div class="field">
        <label id="p3-file-label">Or upload a document <span class="hint">— price list, service menu (PDF, Word, Excel, TXT) — optional</span></label>
        <p id="p3-file-hint" style="font-size:12px;color:var(--text-muted);margin-bottom:10px;line-height:1.5">Your agent will extract products, prices, delivery rules, FAQs — anything useful — from table_1 file.</p>
        <div class="file-upload-box">
          <input type="file" id="catalogue_file" accept=".pdf,.doc,.docx,.xls,.xlsx,.txt" onchange="handleCatalogueFile(this)"/>
          <div class="file-upload-icon">📄</div>
          <div class="file-upload-text">Drop file here or <strong>tap to upload</strong><br/><span style="font-size:11px;color:var(--text-light)">PDF, Word, Excel, TXT — max 10MB</span></div>
        </div>
        <div class="file-chosen" id="catalogue-file-chosen">
          <span class="file-chosen-name" id="catalogue-file-name">—</span>
          <span class="file-remove" onclick="removeCatalogueFile()">✕</span>
        </div>
      </div>

      <div class="btn-row"><button class="btn btn-ghost" onclick="goBack(3)">← Back</button><button class="btn btn-primary" onclick="goNext(3)">Continue →</button></div>
    </div>
  </div>

  <!-- PAGE 4: Photos -->
  <div class="page" id="page-4">
    <div class="card">
      <div class="card-eyebrow">Step 4 of 6</div>
      <div class="card-title" id="p4-title">Add your product photos 📷</div>
      <div class="card-subtitle" id="p4-subtitle">Upload photos so customers can see what you sell. We'll suggest names automatically — just add prices and you're set. <span style="color:var(--text-muted);font-size:13px">Optional — you can skip this for now.</span></div>

      <div class="field">
        <label id="p3-media-label">Your product catalogue <span class="hint">— up to 10 photos</span></label>
        <p id="p3-media-hint" style="font-size:13px;color:var(--text-muted);margin-bottom:14px;line-height:1.5">Upload your product photos. We'll suggest names automatically — just add prices and you're done.</p>
        <div class="media-cards" id="media-cards-container">
          <div class="media-card" id="pcard-0">
            <button class="remove-card" onclick="rmCard(0)" style="display:none">✕</button>
            <div class="media-card-inner">
              <div class="media-img-box" id="pimg-box-0">
                <input type="file" accept="image/*" onchange="handlePImg(this,0)"/>
                <div class="img-ph"><div class="img-ph-icon">📷</div><div class="img-ph-label">Add photo</div></div>
              </div>
              <div class="media-card-fields">
                <label style="margin-bottom:7px" id="p3-item-label-0">Item name</label>
                <input type="text" id="pname-0" placeholder="Analysing..." oninput="S.productCards[0].name=this.value"/>
                <label style="margin-top:8px;margin-bottom:4px;font-size:12px;color:var(--text-muted)">Price (optional)</label>
                <div style="display:flex;align-items:center;gap:4px">
                  <span style="font-size:13px;color:var(--text-muted)">₦</span>
                  <input type="number" id="pprice-0" placeholder="0.00" min="0" step="0.01" style="flex:1" oninput="S.productCards[0].price=this.value"/>
                </div>
              </div>
            </div>
          </div>
        </div>
        <button class="add-media-btn" id="add-product-btn" onclick="addCard()">
          <div class="add-media-btn-icon">+</div>
          <span id="add-btn-text">Add another photo</span>
        </button>
      </div>

      <div class="btn-row"><button class="btn btn-ghost" onclick="goBack(4)">← Back</button><button class="btn btn-primary" onclick="goNext(4)">Continue →</button></div>
    </div>
  </div>

  <!-- PAGE 5: Agent -->
  <div class="page" id="page-5">
    <div class="card">
      <div class="card-eyebrow">Step 5 of 6</div>
      <div class="card-title">Design your agent 🤖</div>
      <div class="card-subtitle">Give your agent a name, personality, and tell it how to address you.</div>

      <div class="field"><label>Agent name <span class="required">*</span></label><input type="text" id="agent_name" placeholder="e.g. Ada, Zara, or MyAssistant" maxlength="30"/><div class="field-error" id="err-agent_name">⚠ Please give your agent a name</div></div>
      <div class="field"><label>What should your agent call you? <span class="required">*</span></label><input type="text" id="preferred_name" placeholder="e.g. Amaka, Boss, or Ma'am" maxlength="30"/><div class="field-error" id="err-preferred_name">⚠ Please enter what your agent should call you</div></div>

      <div class="field">
        <label>Brcolumn_3span class="required">*</span></label>
        <div class="tone-cards">
          <div class="tone-card" onclick="selTone(this,'friendly')">
            <div class="tone-card-emoji">😊</div>
            <div class="tone-card-title">Friendly &amp; Warm</div>
            <div class="tone-card-desc">Casual, approachable. Great for lifestyle, fashion, food.</div>
          </div>
          <div class="tone-card" onclick="selTone(this,'professional')">
            <div class="tone-card-emoji">💼</div>
            <div class="tone-card-title">Professional &amp; Polished</div>
            <div class="tone-card-desc">Confident, formal. Great for services, real estate.</div>
          </div>
          <div class="tone-card" onclick="selTone(this,'energetic')">
            <div class="tone-card-emoji">🔥</div>
            <div class="tone-card-title">Energetic &amp; Bold</div>
            <div class="tone-card-desc">Hype-driven, exciting. Great for content creators.</div>
          </div>
          <div class="tone-card" onclick="selTone(this,'pidgin')">
            <div class="tone-card-emoji">🇳🇬</div>
            <div class="tone-card-title">Naija Vibe</div>
            <div class="tone-card-desc">Pidgin English, street-smart, relatable.</div>
          </div>
        </div>
        <input type="hidden" id="tone_preset"/><div class="field-error" id="err-tone_preset">⚠ Please pick a tone</div>
      </div>

      <div class="field"><label>Extra tone instructions <span class="hint">— optional</span></label><textarea id="tone_extra" placeholder="e.g. Always start with a greeting. Use 'dear' when replying…" maxlength="500" oninput="charCount(this,'tone-c',500)"></textarea><div class="char-count"><span id="tone-c">0</span>/500</div></div>
      <div class="field"><label>Agent rules <span class="hint">— optional</span></label><textarea id="agent_rules" placeholder="e.g. Never promise delivery times I haven't confirmed…" maxlength="500" oninput="charCount(this,'rules-c',500)"></textarea><div class="char-count"><span id="rules-c">0</span>/500</div></div>

      <div class="btn-row"><button class="btn btn-ghost" onclick="goBack(5)">← Back</button><button class="btn btn-primary" onclick="goNext(5)">Review &amp; Submit →</button></div>
    </div>
  </div>

  <!-- PAGE 6: Review -->
  <div class="page" id="page-6">
    <div class="card">
      <div class="card-eyebrow">Step 6 of 6</div>
      <div class="card-title">Almost there ✅</div>
      <div class="card-subtitle">Check everything below. Tap Edit on any section to make changes.</div>
      <div id="review-content"></div>
      <div class="credits-badge">
        <div class="credits-badge-icon">🎁</div>
        <div><strong>Free credits included!</strong> Once you submit, we'll add starter credits to your account so you can explore your agent straight away.</div>
      </div>
      <div class="btn-row"><button class="btn btn-ghost" onclick="goBack(6)">← Back</button><button class="btn btn-primary" id="submit-btn" onclick="submitForm()">Submit &amp; Activate Agent 🚀</button></div>
    </div>
  </div>

</div><!-- /main-content -->

<div class="success-screen" id="success-screen">
  <div class="success-logo-wrap">
    <img class="success-logo" src="${LOGO_B64}" alt="MySquad"/>
  </div>
  <div class="success-title">You're all set! 🎉</div>
  <div class="success-sub">Your agent is being set up now.<br/>Head back to Telegram — you'll get a confirmation message shortly.<br/><br/><span class="success-username" id="success-username"></span>, welcome to MySquad. 🧡</div>
</div>

<div class="loading-overlay" id="loading-overlay">
  <div class="loading-card">
    <img class="loading-logo" src="${LOGO_B64}" alt="MySquad"/>
    <div class="loading-text" id="loading-text">Saving your profile…</div>
  </div>
</div>

<script>
var S={
  token:'${token}',
  nickname:'${nickname}',
  telegram_id:'${tgid}',
  business_type:'',
  business_mode:'',
  primary_biz_category:'',
  also_services:null,
  also_products:null,
  service_delivery_mode:'',
  typical_session_duration:'',
  deposit_policy:'none',
  deposit_custom:'',
  cancellation_policy:'',
  payment_mode:'pay_before',
  reach_channels:[],
  operating_days:[],
  tone_preset:'',
  productCards:[{name:'',file:null,price:null,category:null}],
  cardCount:1,
  catalogueFile:null
};
var RETURNING=${returning};
var SUBMIT_URL='${SUBMIT_URL}';
var DRAFT=${JSON.stringify(draftData)};
var DRAFT_STEP=${draftStep};

function togglePw(id,el){
  var input=document.getElementById(id);
  if(input.type==='password'){input.type='text';el.textContent='🙈';}
  else{input.type='password';el.textContent='👁';}
}

function checkPwMatch(){
  var pw=document.getElementById('password').value;
  var cpw=document.getElementById('confirm_password').value;
  var cpwEl=document.getElementById('confirm_password');
  var hint=document.getElementById('pw-match-hint');
  var errEl=document.getElementById('err-confirm_password');
  if(cpw.length===0){cpwEl.classList.remove('match','error');hint.className='pw-match-hint';hint.textContent='';return;}
  if(pw===cpw){cpwEl.classList.add('match');cpwEl.classList.remove('error');hint.className='pw-match-hint show ok';hint.innerHTML='✓ Passwords match';errEl.classList.remove('show');}
  else{cpwEl.classList.remove('match');hint.className='pw-match-hint show no';hint.innerHTML='✗ Passwords do not match yet';errEl.classList.remove('show');}
}

function normalisePhone(el){
  var v=el.value.replace(/[^+\d]/g,'');
  // Convert 0XXXXXXXXX → +234XXXXXXXXX
  if(/^0[7-9][0-1]\d{8}$/.test(v)){
    v='+234'+v.slice(1);
    el.value=v;
  }
  // Show hint if looks valid
  var hint=document.getElementById('wa-format-hint');
  if(hint){
    var clean=v.replace(/\D/g,'');
    if(clean.length>=10){hint.style.display='block';hint.textContent='✓ '+v;}
    else{hint.style.display='none';}
  }
}
