function valPage(p){
  var ok=true;
  function req(id,test){
    var el=document.getElementById(id);if(!el)return true;
    var v=el.value.trim();var pass=test?test(v):v.length>0;
    var err=document.getElementById('err-'+id);
    if(err)err.classList.toggle('show',!pass);
    el.classList.toggle('error',!pass);
    if(pass)el.classList.remove('error');
    if(!pass)ok=false;return pass;
  }
  if(p===1){
    req('first_name');req('last_name');
    req('email', function(v) { return v.includes('@') && v.includes('.') && v.length >= 5 && !v.includes(' ');
    });
    req('whatsapp_number',function(v){return v.replace(/\s/g,'').length>=10;});
    req('location');
    req('username',function(v){return/^[a-zA-Z0-9_]{3,30}$/.test(v);});
    req('password',function(v){return v.length>=8;});
    var pw=document.getElementById('password').value;
    var cpw=document.getElementById('confirm_password').value;
    var cpwEl=document.getElementById('confirm_password');
    var errMatch=document.getElementById('err-confirm_password');
    var hint=document.getElementById('pw-match-hint');
    var match=pw===cpw&&cpw.length>0;
    if(!match){errMatch.classList.add('show');cpwEl.classList.add('error');cpwEl.classList.remove('match');hint.className='pw-match-hint';ok=false;}
    else{errMatch.classList.remove('show');}
  } else if(p===2){
    req('business_name');
    var btVal=document.getElementById('business_type').value.trim();
    var errBt=document.getElementById('err-business_type');
    if(!btVal){errBt.classList.add('show');ok=false;}else{errBt.classList.remove('show');}
    req('business_location');
    req('business_description',function(v){return v.length>=30;});
    var pmWrap=document.getElementById('payment-mode-wrap');
    if(pmWrap.classList.contains('show')){
      var pmVal=document.getElementById('payment_mode').value;
      var errPm=document.getElementById('err-payment_mode');
      if(!pmVal){errPm.classList.add('show');ok=false;}else{errPm.classList.remove('show');}
    }
  } else if(p===5){
    req('agent_name');req('preferred_name');
    if(!S.tone_preset){document.getElementById('err-tone_preset').classList.add('show');ok=false;}
    else{document.getElementById('err-tone_preset').classList.remove('show');}
  }
  return ok;
}

