async function handlePImg(input,idx){
  var file=input.files[0];if(!file)return;
  if(file.size>5*1024*1024){alert('Image must be under 5MB');return;}
  S.productCards[idx]=S.productCards[idx]||{};
  S.productCards[idx].file=file;
  var reader=new FileReader();
  reader.onload=function(e){
    var box=document.getElementById('pimg-box-'+idx);
    box.innerHTML='<img src="'+e.target.result+'" alt="photo"/><input type="file" accept="image/*" onchange="handlePImg(this,'+idx+')"/>';
    var card=document.getElementById('pcard-'+idx);
    if(card)card.querySelector('.remove-card').style.display='flex';
  };
  reader.readAsDataURL(file);
  var nameInput=document.getElementById('pname-'+idx);
  if(nameInput)nameInput.placeholder='Analysing...';
  try{
    var b64=await new Promise(function(res){
      var r=new FileReader();
      r.onload=function(e){res(e.target.result.split(',')[1]);};
      r.readAsDataURL(file);
    });
    var resp=await fetch('/webhook/vision-analyse',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({image_b64:b64,mime_type:file.type})
    });
    var result=await resp.json();
    if(result.suggested_name){
      S.productCards[idx].name=result.suggested_name;
      if(nameInput){nameInput.value=result.suggested_name;nameInput.placeholder='Item name';}
    }else{
      if(nameInput)nameInput.placeholder='Item name';
    }
    if(result.suggested_category)S.productCards[idx].category=result.suggested_category;
  }catch(e){
    if(nameInput)nameInput.placeholder='Item name';
  }
}
