  var prods=S.productCards.filter(Boolean).filter(function(c){return c.file||c.name;});
  prods.forEach(function(p,i){fd.append('product_name_'+i,p.name||'');fd.append('product_price_'+i,p.price||'');fd.append('product_category_'+i,p.category||'');if(p.file)fd.append('product_image_'+i,p.file,p.file.name);});
  fd.append('product_count',prods.length);
  document.getElementById('loading-text').textContent='Submitting your details…';
  try{
