return { json: { html_content: html } };

const rows = $input.all();
if (!rows.length) return { json: { text: '' } };
const headers = Object.keys(rows[0].json);
const lines = [
  headers.join('\t'),
  ...rows.map(r => headers.map(h => String(r.json[h] ?? '')).join('\t'))
];
return { json: { text: lines.join('\n') } };

const webhookBody  = $('Form Submission Webhook').first().json.body || {};
const extractedText = ($json.data || $json.text || '').trim();

const returning         = (webhookBody.returning === '1');
const skip_personal_update = returning;

const token             = (webhookBody.token           || '').trim();
const telegram_id       = (webhookBody.telegram_id     || '').trim();
const nickname          = (webhookBody.nickname         || '').trim();
const first_name        = returning ? '' : (webhookBody.first_name       || '').trim();
const last_name         = returning ? '' : (webhookBody.last_name        || '').trim();
const full_name         = returning ? '' : [first_name, last_name].filter(Boolean).join(' ');
const email             = returning ? '' : (webhookBody.email            || '').trim().toLowerCase();
const whatsapp_no       = returning ? '' : (webhookBody.whatsapp_number  || '').trim().replace(/\s+/g, '');
const location          = returning ? '' : (webhookBody.location         || '').trim();
const username          = returning ? '' : (webhookBody.username         || '').trim().toLowerCase();
const password          = returning ? '' : (webhookBody.password          || '');
const preferred_name    = (webhookBody.preferred_name   || '').trim() || first_name;

const business_name        = (webhookBody.business_name        || '').trim();
const business_type        = (webhookBody.business_type        || '').trim();
const business_location    = (webhookBody.business_location    || '').trim();
const business_description = (webhookBody.business_description || '').trim();

const business_mode           = (webhookBody.business_mode           || 'product_only').trim();
const service_delivery_mode   = (webhookBody.service_delivery_mode   || '').trim();
const typical_session_duration= (webhookBody.typical_session_duration|| '').trim();
const deposit_policy          = (webhookBody.deposit_policy          || 'none').trim();
const deposit_custom_text     = (webhookBody.deposit_custom_text     || '').trim();
const cancellation_policy     = (webhookBody.cancellation_policy     || '').trim();
const payment_mode            = (webhookBody.payment_mode            || 'pay_before').trim();

let reach_channels = [];
let operating_days = [];
try { reach_channels = JSON.parse(webhookBody.reach_channels || '[]'); } catch(e) {}
try { operating_days = JSON.parse(webhookBody.operating_days  || '[]'); } catch(e) {}
if (!Array.isArray(reach_channels)) reach_channels = [];
if (!Array.isArray(operating_days))  operating_days  = [];

const open_time  = webhookBody.open_time  || '08:00';
const close_time = webhookBody.close_time || '18:00';

const catalogue_text      = (webhookBody.catalogue_text       || '').trim();
const has_catalogue_file  = (webhookBody.has_catalogue_file   === '1');
const catalogue_file_name = webhookBody.catalogue_file_name   || '';
const catalogue_file_type = webhookBody.catalogue_file_type   || '';

let final_catalogue_text = catalogue_text;
let file_was_processed   = false;
if (extractedText.length > 10) {
  file_was_processed   = true;
  final_catalogue_text = catalogue_text
    ? catalogue_text + '\n\n--- From table_2 document ---\n' + extractedText
    : extractedText;
}

const tone_preset  = (webhookBody.tone_preset  || 'friendly').trim();
const tone_extra   = (webhookBody.tone_extra   || '').trim();
const agent_name   = (webhookBody.agent_name   || 'MyAgent').trim();
const agent_rules  = (webhookBody.agent_rules  || '').trim();

const product_count = parseInt(webhookBody.product_count || '0', 10);
const products = [];
for (let i = 0; i < product_count; i++) {
  const name     = (webhookBody[`product_name_${i}`]     || '').trim();
  const price    = (webhookBody[`product_price_${i}`]    || '').trim();
  const category = (webhookBody[`product_category_${i}`] || '').trim();
  products.push({
    name:        name || `product_${i}`,
    price:       price ? parseFloat(price) : null,
    category:    category || null,
    binary_key:  `product_image_${i}`
  });
}

if (!token)       throw new Error('Missing onboarding token');
if (!telegram_id) throw new Error('Missing telegram_id');

return { json: {
  token, telegram_id, nickname, first_name, last_name, full_name,
  email, whatsapp_no, location, username, password, preferred_name,
  business_name, business_type, business_location, business_description,
  business_mode, service_delivery_mode, typical_session_duration,
  deposit_policy, deposit_custom_text, cancellation_policy, payment_mode,
  reach_channels, operating_days, open_time, close_time,
  catalogue_text, has_catalogue_file, catalogue_file_name, catalogue_file_type,
  final_catalogue_text, file_was_processed,
  tone_preset, tone_extra, agent_name, agent_rules,
  product_count, products,
  returning, skip_personal_update
}};

const tokenRow = $json;
if (!tokenRow || !tokenRow.tenant_id) throw new Error('Token invalid, expired, or already used');
if (new Date(tokenRow.expires_at) <= new Date()) throw new Error('Token expired');
const formData = $('Extract Form Fields').first().json;
return { json: { ...formData, tenant_id: tokenRow.tenant_id, token_expires: tokenRow.expires_at } };

const raw = ($json.output || $json.text || '{}').replace(/```json|```/g, '').trim();
const prevData = $('Build Password Hash').first().json;  // ✅ use the node with full data + hash
let businessExtra = {};
try {
  businessExtra = JSON.parse(raw);
} catch(e) {
  businessExtra = {
    business_category: prevData.business_type || '',
    target_customers: 'General customers',
    unique_selling_point: '',
    key_services: []
  };
}
return { json: { ...prevData, business_extra: businessExtra } };

const d = $('Parse Business AI Response').first().json;
const raw = ($json.output || $json.text || '{}').replace(/```json|```/g,'').trim();
let parsed = {};
try { parsed = JSON.parse(raw); }
catch(e) { parsed = { catalogue_items: [], business_context: '', extra_facts: [] }; }

const catalogueItems  = Array.isArray(parsed.catalogue_items) ? parsed.catalogue_items : [];
const businessContext = (parsed.business_context || '').trim();
const extraFacts      = Array.isArray(parsed.extra_facts) ? parsed.extra_facts : [];

const catalogueSummary = catalogueItems.length > 0
  ? catalogueItems.map(p => {
      let line = p.name;
      if (p.price) line += ': ' + p.price;
      if (p.description) line += ' — ' + p.description;
      if (p.item_type === 'service') line += ' [service]';
      return line;
    }).join('\n')
  : (d.final_catalogue_text || '');

const enrichedDescription = businessContext
  ? (d.business_description || '') + (d.business_description ? '\n\n' : '') + businessContext
  : (d.business_description || '');

const toneMap = {
  friendly:     { formality:2, uses_pidgin:false, language_mix:'english', tone_summary:'friendly and warm, approachable' },
  professional: { formality:4, uses_pidgin:false, language_mix:'english', tone_summary:'professional and polished, confident' },
  energetic:    { formality:2, uses_pidgin:false, language_mix:'english', tone_summary:'energetic and bold, high energy' },
  pidgin:       { formality:1, uses_pidgin:true,  language_mix:'pidgin',  tone_summary:'naija vibe, pidgin english, relatable' }
};
const toneProfile = { ...(toneMap[d.tone_preset] || toneMap.friendly) };
if (d.tone_extra) toneProfile.extra_instructions = d.tone_extra;

const rulesArray = d.agent_rules
  ? d.agent_rules.split(/[\n;]/).map(r => r.trim()).filter(r => r.length > 5)
  : [];

// ── Derive final deposit policy label ──
const depositLabel = {
  none:         'No deposit required',
  '50_percent': '50% deposit required upfront to confirm booking',
  full_payment: 'Full payment required upfront to confirm booking',
  custom:       d.deposit_custom_text || 'Custom deposit required'
}[d.deposit_policy] || 'No deposit required';

return { json: {
  ...d,
  catalogue_parsed:      catalogueItems,
  catalogue_summary:     catalogueSummary,
  enriched_description:  enrichedDescription,
  extra_facts:           extraFacts,
  tone_profile:          toneProfile,
  rules_array:           rulesArray,
  deposit_label:         depositLabel
}};

const d = $('Build Full Config').first().json;
const tenant_id   = d.tenant_id;
const business_id = $('Save Business Profile').first().json.id;

const memories = [
  { key: 'business_name',       value: d.business_name },
  { key: 'business_type',       value: d.business_type },
  { key: 'business_mode',       value: d.business_mode || 'product_only' },
  { key: 'business_location',   value: d.business_location },
  { key: 'owner_nickname',      value: d.nickname || d.first_name },
  { key: 'operating_hours',     value: `${d.open_time} to ${d.close_time} on ${(d.operating_days||[]).join(', ')||'weekdays'}` },
  { key: 'how_customers_reach', value: (d.reach_channels||[]).join(', ') },
  { key: 'agent_tone',          value: d.tone_profile?.tone_summary || d.tone_preset },
  { key: 'payment_mode',        value: d.payment_mode || 'pay_before' }
];

const isService = ['service_only','hybrid_product_led','hybrid_service_led'].includes(d.business_mode);
if (isService) {
  if (d.service_delivery_mode) {
    const deliveryLabels = {
      client_comes_to_us: 'Clients come to the business location',
      we_go_to_client:    'Business goes to the client location',
      both:               'Both — depends on the service'
    };
    memories.push({ key: 'service_delivery_mode', value: deliveryLabels[d.service_delivery_mode] || d.service_delivery_mode });
  }
  if (d.typical_session_duration) {
    const durationLabels = {
      '30min': '30 minutes', '1hr': '1 hour', '2hr': '2 hours',
      half_day: 'Half day', full_day: 'Full day', varies: 'Varies by service'
    };
    memories.push({ key: 'typical_session_duration', value: durationLabels[d.typical_session_duration] || d.typical_session_duration });
  }
  if (d.deposit_label) memories.push({ key: 'deposit_policy', value: d.deposit_label });
  if (d.cancellation_policy?.trim()) memories.push({ key: 'cancellation_policy', value: d.cancellation_policy.trim() });
}

if (d.business_extra?.target_customers)     memories.push({ key: 'target_customers',     value: d.business_extra.target_customers });
if (d.business_extra?.unique_selling_point) memories.push({ key: 'unique_selling_point', value: d.business_extra.unique_selling_point });
if (d.catalogue_summary)                    memories.push({ key: 'product_catalogue',    value: d.catalogue_summary.substring(0,800) });
(d.extra_facts||[]).forEach((fact,idx) => {
  if (fact?.trim()) memories.push({ key: `extra_fact_${idx+1}`, value: fact.trim(), source: 'onboarding_document' });
});

return memories
  .filter(m => m.value && String(m.value).trim())
  .map(m => ({ json: { tenant_id, business_id, key: m.key, value: String(m.value), source: m.source||'onboarding', confidence: 1.0 } }));

const d = $('Build Full Config').first().json;
const products    = d.products || [];
const tenant_id   = d.tenant_id;
const business_id = $('Save Business Profile').first().json.id;
const webhookBinary = $('Form Submission Webhook').first().binary || {};
const items = [];

for (const product of products) {
  if (!product?.name) continue;
  const bd = webhookBinary[product.binary_key];
  if (!bd) continue;
  const slug = product.name.toLowerCase().replace(/[^a-z0-9]/g,'-').replace(/-+/g,'-').replace(/^-|-$/g,'');
  const ext = (bd.mimeType||'image/jpeg').split('/')[1]||'jpg';
  const key = `${tenant_id}/${business_id}/products/${slug}.${ext}`;
  items.push({
    json: {
      tenant_id,
      business_id,
      product_name:     product.name,
      product_price:    product.price    ?? null,
      product_category: product.category ?? null,
      object_key:       key,
      mime_type:        bd.mimeType || 'image/jpeg',
      binary_key:       product.binary_key
    },
    binary: { data: bd }
  });
}
return items;

