parameters.jsCode:
const items = $input.all();
const chatId = String($('Telegram Trigger').first().json.callback_query.message.chat.id);

const businesses = items
  .map(i => i.json)
  .filter(b => b.business_id)
  .map((b, idx) => ({
    index: idx + 1,
    business_id: b.business_id,
    business_name: b.business_name,
    wa_instance: b.wa_instance || null,
    wa_number: b.wa_number || null,
    wa_active: b.wa_active === true || b.wa_active === 'true'
  }));

if (businesses.length === 0) {
  return [{ json: {
    error: 'no_businesses',
    chatId,
    businesses: [],
    hasMultiple: false,
    selectedBusinessId: null,
    selectedBusinessName: null,
    selectedWaNumber: null,
    selectedWaActive: false,
    selectedWaInstance: null
  } }];
}

const hasMultiple = businesses.length > 1;
const selected = hasMultiple ? null : businesses[0];

return [{ json: {
  chatId,
  businesses,
  hasMultiple,
  selectedBusinessId: selected ? selected.business_id : null,
  selectedBusinessName: selected ? selected.business_name : null,
  selectedWaNumber: selected ? (selected.wa_number || null) : null,
  selectedWaActive: selected ? (selected.wa_active || false) : false,
  selectedWaInstance: selected ? (selected.wa_instance || null) : null
} }];

const responseText = ($json.data && $json.data.text ? $json.data.text : '').trim();
const businesses = $('Build WA Context').first().json.businesses || [];
const chatId = $('Build WA Context').first().json.chatId;

const num = parseInt(responseText, 10);
if (isNaN(num) || num < 1 || num > businesses.length) {
  throw new Error('Invalid selection "' + responseText + '". Please type a number between 1 and ' + businesses.length + '.');
}

const selected = businesses[num - 1];
return [{ json: {
  chatId,
  businesses,
  selectedBusinessId: selected.business_id,
  selectedBusinessName: selected.business_name,
  selectedWaNumber: selected.wa_number || null,
  selectedWaActive: selected.wa_active || false,
  selectedWaInstance: selected.wa_instance || null
} }];

const input = ($json.data && $json.data.text ? $json.data.text : '').trim().replace(/[\s\+\-\(\)]/g, '');

const buildCtx = $('Build WA Context').first().json;
const chatId = buildCtx.chatId;
const businessId = buildCtx.hasMultiple
  ? $('Resolve Business Selection').first().json.selectedBusinessId
  : buildCtx.businesses[0].business_id;
const businessName = buildCtx.hasMultiple
  ? $('Resolve Business Selection').first().json.selectedBusinessName
  : buildCtx.businesses[0].business_name;

if (!/^\d{7,15}$/.test(input)) {
  throw new Error('Invalid phone number: "' + input + '". Use digits only with country code, e.g. 2348105465541');
}

const instanceName = 'msq_' + businessId;
return [{ json: { chatId, phoneNumber: input, businessId, businessName, instanceName } }];

